// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

// VIOLATION #1: delegatecall in fallback to arbitrary target
contract UnrestrictedDelegatecall {
    address public owner;

    fallback(bytes calldata data) external returns (bytes memory) {
        (bool success, bytes memory ret) = owner.delegatecall(data);
        require(success, "delegatecall failed");
        return ret;
    }
}

// VIOLATION #2: state modification in receive()
contract StatefulReceive {
    mapping(address => uint256) public balances;

    receive() external payable {
        balances[msg.sender] = msg.value;
    }
}

// VIOLATION #3: arbitrary external call in fallback
contract ArbitraryCall {
    fallback(bytes calldata) external payable {
        address target = abi.decode(msg.data[4:], (address));
        (bool success,) = target.call{value: msg.value}("");
        require(success);
    }
}

// VIOLATION #4: reentrancy-vulnerable ETH transfer in fallback
contract ReentrancyFallback {
    receive() external payable {
        (bool success,) = msg.sender.call{value: address(this).balance}("");
        require(success);
    }
}

// VIOLATION #5: complex logic with loops in fallback
contract LoopyFallback {
    mapping(address => uint256) public pending;
    address[] public recipients;

    fallback() external payable {
        for (uint256 i = 0; i < recipients.length; i++) {
            pending[recipients[i]] += msg.value / recipients.length;
        }
    }
}

// SAFE: receive() that just accepts ETH without state changes
contract SafeReceiver {
    receive() external payable {}
}

// SAFE: fallback with revert
contract SafeRejecter {
    fallback() external payable {
        revert("Contract does not accept direct calls");
    }
}

// SAFE: receive() with only event emission
contract SafeEventReceiver {
    event Received(address indexed sender, uint256 amount);

    receive() external payable {
        emit Received(msg.sender, msg.value);
    }
}
